import sys
from typing import Optional, List
import random

sys.setrecursionlimit(5000)


class TreeNode:
    def __init__(self, val: int = 0):
        self.val = val
        self.left: Optional['TreeNode'] = None
        self.right: Optional['TreeNode'] = None
        self.parent: Optional['TreeNode'] = None


class Solution:
    def maxPoints(self, root: Optional['TreeNode'], b_leaf: 'TreeNode') -> int:
        if root is None:
            return 0

        # Step 1: climb from B's leaf to the root -> contested nodes + leaf depth L
        b_path = set()
        node = b_leaf
        count = 0
        while node is not None:
            b_path.add(id(node))
            node = node.parent
            count += 1
        leaf_depth = count - 1  # L = depth of B's leaf from the root

        # Step 2: per-node value to A (fixed, path-independent)
        def gain(n: 'TreeNode', depth: int) -> int:
            if id(n) in b_path:
                if 2 * depth < leaf_depth:      # A arrives earlier -> full
                    return n.val
                elif 2 * depth == leaf_depth:   # tie -> half (integer division)
                    return n.val // 2
                else:                           # B arrives earlier -> nothing
                    return 0
            return n.val                        # B never visits -> full

        # Step 3: best root-to-leaf weighted path
        def dfs(n: 'TreeNode', depth: int) -> int:
            g = gain(n, depth)
            if n.left is None and n.right is None:
                return g
            best_child = 0
            if n.left:
                best_child = max(best_child, dfs(n.left, depth + 1))
            if n.right:
                best_child = max(best_child, dfs(n.right, depth + 1))
            return g + best_child

        return dfs(root, 0)


# ---------- Brute-force oracle: enumerate every root-to-leaf path, simulate ----------
class BruteSolution:
    def maxPoints(self, root: Optional['TreeNode'], b_leaf: 'TreeNode') -> int:
        if root is None:
            return 0
        # B's arrival time at each node on its path: time = distance from leaf
        b_time = {}
        node, t = b_leaf, 0
        while node is not None:
            b_time[id(node)] = t
            node = node.parent
            t += 1

        best = [0]

        def walk(n, depth, acc):
            # A reaches n at time = depth
            if id(n) in b_time:
                bt = b_time[id(n)]
                if depth < bt:
                    pts = n.val
                elif depth == bt:
                    pts = n.val // 2
                else:
                    pts = 0
            else:
                pts = n.val
            acc += pts
            if n.left is None and n.right is None:
                best[0] = max(best[0], acc)
                return
            if n.left:
                walk(n.left, depth + 1, acc)
            if n.right:
                walk(n.right, depth + 1, acc)

        walk(root, 0, 0)
        return best[0]


# ---------- helpers ----------
def link(parent, left=None, right=None):
    parent.left = left
    parent.right = right
    if left:
        left.parent = parent
    if right:
        right.parent = parent


def build_sample():
    n10, n5, n8, n3, n6 = (TreeNode(v) for v in (10, 5, 8, 3, 6))
    link(n10, n5, n8)
    link(n5, n3, n6)
    return n10, n6  # root, B's leaf


def random_tree(max_nodes):
    vals = [random.randint(1, 1000) for _ in range(max_nodes)]
    nodes = [TreeNode(v) for v in vals]
    leaves = []
    for i in range(1, len(nodes)):
        p = nodes[random.randint(0, i - 1)]
        if p.left is None and random.random() < 0.5:
            p.left = nodes[i]; nodes[i].parent = p
        elif p.right is None:
            p.right = nodes[i]; nodes[i].parent = p
        elif p.left is None:
            p.left = nodes[i]; nodes[i].parent = p
        else:
            # parent full; attach to its child slot search (simple fallback)
            for q in nodes[:i]:
                if q.left is None:
                    q.left = nodes[i]; nodes[i].parent = q; break
                if q.right is None:
                    q.right = nodes[i]; nodes[i].parent = q; break
    root = nodes[0]
    leaves = [x for x in nodes if x.left is None and x.right is None]
    return root, random.choice(leaves)


if __name__ == "__main__":
    sol, brute = Solution(), BruteSolution()

    root, bleaf = build_sample()
    print("sample:", sol.maxPoints(root, bleaf), "(expected 18)")

    # single node (root is the only leaf, B starts there)
    single = TreeNode(7)
    print("single node val 7:", sol.maxPoints(single, single), "(tie -> 7//2 = 3)")

    # randomized differential test vs brute oracle
    random.seed(1)
    ok = True
    for _ in range(3000):
        r, bl = random_tree(random.randint(1, 14))
        a, b = sol.maxPoints(r, bl), brute.maxPoints(r, bl)
        if a != b:
            ok = False
            print("MISMATCH", a, b)
            break
    print("3000 random differential tests:", "ALL PASS" if ok else "FAILED")

    # chain stress: depth ~1000 (recursion limit)
    chain = [TreeNode(i % 1000 + 1) for i in range(1000)]
    for i in range(1, 1000):
        chain[i - 1].left = chain[i]; chain[i].parent = chain[i - 1]
    print("chain n=1000:", sol.maxPoints(chain[0], chain[-1]), "(runs without recursion error)")
